import React from "react";
import './project3.css'

function Project3() {
    return (
      <div id="project3-body" className="animate__animated animate__fadeInDown">
          <h4>The Closet</h4>
          <p id="project3-description">
            A full stack e-commerce clothing application. This project was developed as a group project, utilizing agile devlopment practices. Tech stack: REACT, HTML/CSS, Bootstrap, Node, Express, PostgreSQL



            A REACT app that allows users to register an account, build fitness routines, create custom workouts, and browse routines and activities created by other users. Tech stack: REACT, JSON, REST API, HTML/CSS, Bootstrap, Node, Express, and PostgreSQL.
          </p>
          <div>
            <ul id="project3-links-ul">
                <li id="project3-link1"><a id="project1-link1" href="https://wonderful-baklava-d81c60.netlify.app">View Site</a></li>
                <li id="project3-link2"><a id="project1-link2" href="https://github.com/ameyer12/FitnessTrackrFrontEnd">GitHub</a></li>
            </ul>
          </div>
      </div>
    )
  }

export default Project3;
